return [{
  json: {
    workflow_id: 'CWF-140',
    vein: 'research_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    selected_topic: $json.selected_topic || {},
    route_id: $json.route_id || 'ROUTE-001',
    execution_timestamp: new Date().toISOString()
  }
}];

const topic = $json.selected_topic || {};
const research_sources = [
  { source_id: 'SRC-001', name: 'Academic Research', type: 'scholarly', credibility: 0.95, documents_count: 12 },
  { source_id: 'SRC-002', name: 'Industry Reports', type: 'commercial', credibility: 0.85, documents_count: 8 },
  { source_id: 'SRC-003', name: 'News Archives', type: 'media', credibility: 0.75, documents_count: 25 }
];

const evidence_synthesis = {
  main_claim: topic.topic_statement || 'Research topic',
  supporting_claims: [
    { claim: 'Supporting evidence point 1', sources: ['SRC-001', 'SRC-002'], confidence: 0.88 },
    { claim: 'Supporting evidence point 2', sources: ['SRC-002', 'SRC-003'], confidence: 0.82 }
  ],
  contradictions: [],
  evidence_gaps: ['Additional verification needed'],
  overall_confidence: 0.85
};

return [{
  json: {
    ...$json,
    research_sources: research_sources,
    evidence_synthesis: evidence_synthesis,
    synthesis_complete: true
  }
}];

const synthesis = $json.evidence_synthesis || {};
const sources = $json.research_sources || [];

const research_packet = {
  instance_id: 'RSP-' + Date.now(),
  artifact_family: 'research_synthesis_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-140-Research-Synthesis',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    topic_statement: $json.selected_topic.topic_statement,
    main_claim: synthesis.main_claim,
    supporting_claims: synthesis.supporting_claims,
    research_sources: sources,
    evidence_confidence: synthesis.overall_confidence,
    contradictions_found: synthesis.contradictions && synthesis.contradictions.length > 0,
    gaps_identified: synthesis.evidence_gaps || [],
    ready_for_script_generation: synthesis.overall_confidence > 0.75 && !synthesis.contradictions.length
  }
};

return [{ json: research_packet }];

return [{
  json: {
    workflow_id: 'CWF-140',
    execution_status: 'SUCCESS',
    next_workflow: 'WF-200',
    research_packet: $json,
    decision: $json.payload.ready_for_script_generation ? 'PROCEED_TO_SCRIPT_GENERATION' : 'NEEDS_EVIDENCE_REFINEMENT'
  }
}];
